def lambda_handler(event, context):
    # Deserialize the JSON payload from the event
    try:
        user_actions = json.loads(event['body'])
    except json.JSONDecodeError as e:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Invalid JSON payload'})
        }
    
    # Process the user actions (example processing logic)
    processed_data = process_user_actions(user_actions)
    
    # Serialize the processed data using pickle
    serialized_data = pickle.dumps(processed_data)
    
    return {
        'statusCode': 200,
        'body': json.dumps({'message': 'Data processed successfully', 'data': serialized_data.hex()})
    }

def process_user_actions(actions):
    # Example processing logic (replace with actual processing)
    processed = []
    for action in actions:
        if action['type'] == 'update':
            processed.append(f"Updated {action['item']} to {action['value']}")
        elif action['type'] == 'delete':
            processed.append(f"Deleted {action['item']}")
    return processed